import React, { useCallback, useState } from 'react';
import { useDropzone } from 'react-dropzone';

const s = {
  zone: (active, hasError) => ({
    border: `2px dashed ${active ? '#1e40af' : hasError ? '#dc2626' : '#9ca3af'}`,
    borderRadius: 8,
    padding: '40px 24px',
    textAlign: 'center',
    cursor: 'pointer',
    background: active ? '#eff6ff' : '#f9fafb',
    transition: 'all 0.2s ease',
  }),
  iconContainer: {
    width: 56,
    height: 56,
    borderRadius: '50%',
    background: '#e5e7eb',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    margin: '0 auto 16px',
  },
  icon: {
    width: 24,
    height: 24,
    stroke: '#6b7280',
    strokeWidth: 2,
    fill: 'none',
  },
  title: { 
    fontWeight: 600, 
    fontSize: 15, 
    color: '#111827', 
    marginBottom: 6,
    letterSpacing: '-0.01em',
  },
  sub: { 
    fontSize: 13, 
    color: '#6b7280',
    lineHeight: 1.5,
  },
  formats: {
    fontSize: 12,
    color: '#9ca3af',
    marginTop: 8,
    fontWeight: 500,
  },
  fileList: { marginTop: 20 },
  fileItem: {
    display: 'flex',
    alignItems: 'center',
    gap: 12,
    padding: '12px 16px',
    background: '#fff',
    border: '1px solid #e5e7eb',
    borderRadius: 6,
    marginBottom: 8,
    fontSize: 13,
  },
  fileIcon: {
    width: 32,
    height: 32,
    borderRadius: 4,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: 11,
    fontWeight: 700,
    color: '#fff',
  },
  fileName: {
    flex: 1,
    overflow: 'hidden',
    textOverflow: 'ellipsis',
    whiteSpace: 'nowrap',
    color: '#1f2937',
    fontWeight: 500,
  },
  fileSize: { 
    color: '#9ca3af', 
    fontSize: 12,
    minWidth: 50,
    textAlign: 'right',
  },
  removeBtn: {
    background: 'none',
    border: 'none',
    color: '#9ca3af',
    cursor: 'pointer',
    fontSize: 18,
    lineHeight: 1,
    padding: '4px 8px',
    borderRadius: 4,
    transition: 'all 0.2s',
  },
  errorText: {
    color: '#dc2626',
    fontSize: 12,
    marginTop: 8,
    fontWeight: 500,
  },
};

export default function UploadZone({ files, setFiles, error }) {
  const onDrop = useCallback((accepted, rejected) => {
    // Handle rejected files first
    if (rejected && rejected.length > 0) {
      const rejectedNames = rejected.map(r => r.file.name).join(', ');
      console.warn('Rejected files:', rejectedNames);
    }

    // Replace all previous files with newly selected ones (don't accumulate)
    if (accepted && accepted.length > 0) {
      setFiles(accepted);
    }
  }, [setFiles]);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: { 
      'application/pdf': ['.pdf'], 
      'application/vnd.openxmlformats-officedocument.wordprocessingml.document': ['.docx'],
      'application/msword': ['.doc']
    },
    maxSize: 10 * 1024 * 1024, // 10MB limit
  });

  const remove = (name) => setFiles(prev => prev.filter(f => f.name !== name));

  const formatFileSize = (bytes) => {
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
    return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
  };

  return (
    <div>
      <div {...getRootProps()} style={s.zone(isDragActive, !!error)}>
        <input {...getInputProps()} />
        <div style={s.iconContainer}>
          <svg style={s.icon} viewBox="0 0 24 24">
            <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
            <polyline points="17 8 12 3 7 8" />
            <line x1="12" y1="3" x2="12" y2="15" />
          </svg>
        </div>
        <div style={s.title}>
          {isDragActive ? 'Drop files here' : 'Drag & drop resumes here'}
        </div>
        <div style={s.sub}>or click to browse from your computer</div>
        <div style={s.formats}>Supported formats: PDF, DOCX (Max 10MB)</div>
        {error && <div style={s.errorText}>{error}</div>}
      </div>

      {files.length > 0 && (
        <div style={s.fileList}>
          {files.map(f => (
            <div key={f.name} style={s.fileItem}>
              <div style={{ 
                ...s.fileIcon, 
                background: f.name.toLowerCase().endsWith('.pdf') ? '#dc2626' : '#2563eb' 
              }}>
                {f.name.toLowerCase().endsWith('.pdf') ? 'PDF' : 'DOC'}
              </div>
              <span style={s.fileName}>{f.name}</span>
              <span style={s.fileSize}>{formatFileSize(f.size)}</span>
              <button 
                style={s.removeBtn} 
                onClick={(e) => {
                  e.stopPropagation();
                  remove(f.name);
                }}
                onMouseOver={(e) => e.target.style.color = '#dc2626'}
                onMouseOut={(e) => e.target.style.color = '#9ca3af'}
              >
                ×
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
